INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-6f0ba476-moex-00420', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司2022年度按應計基礎認列現銷總額$680,000（發生銷貨折扣$39,000）及賒銷總額$950,000 （發生銷貨退回及折讓$53,000），2022 年應收帳款期初與期末總額分別為$320,000 與$250,000， 沖銷呆帳$12,000，則甲公司2022年度現金基礎下之銷貨收入為何？', '["$1,456,000", "$1,468,000", "$1,596,000", "$1,608,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "5e8d2b41a0ff", "answer_pdf_sha1": "fc2ea2237657", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00421', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司2022年由營業產生之現金流量為$47,500，其中應收帳款淨額減少$3,000，折舊費用$3,600， 應付帳款增加$1,700，預付款項增加$900，長期債券投資折價攤銷$600，出售不動產、廠商及設 備損失$2,200，發行公司債收現$20,000，試問甲公司2022年淨利為多少？（該公司將收取之利息 分類為營業活動現金流量）', '["$37,300", "$38,500", "$40,700", "$58,500"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "5e8d2b41a0ff", "answer_pdf_sha1": "fc2ea2237657", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00422', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司2022年帳上有6%特別股12,000股，每股面額$100，普通股，1月1日流通在外200,000 股，3月1日現金增資發行新股60,000股，7月1日收回庫藏股票20,000股，10月1日再售出全 部庫藏股票。若甲公司2022年淨利為$580,000，試計算其每股盈餘：（取最接近數值之選項）', '["$1.99", "$2.07", "$2.27", "$2.37"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "5e8d2b41a0ff", "answer_pdf_sha1": "fc2ea2237657", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00423', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '長江公司以每股$35 購買松花公司股票 8,000 股，並支付手續費$399，長江公司將這些股票歸類 為透過其他綜合損益按公允價值衡量之金融資產。假設松花公司股票年底之市價為每股$33，公司 如於此時出售將支付手續費及稅捐$1,168，試問下列有關公司年底對此股票之評價處理為何？', '["將產生評價損失$14,832", "將產生評價損失$15,231", "將產生評價損失$16,000", "將產生評價損失$16,399"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "5e8d2b41a0ff", "answer_pdf_sha1": "fc2ea2237657", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00424', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司於 2021 年初向銀行取得 5 年期借款$800,000 以增擴廠房用途，並以此廠房作為抵押品。 銀行要求此5年期借款，需每年底償付固定數額$208,349，其中有效利率為8.5%。試問甲公司於 2022年度損益表，針對此借款所認列之利息費用為多少？（取最接近整數之選項）', '["$50,290", "$54,400", "$56,070", "$68,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "5e8d2b41a0ff", "answer_pdf_sha1": "fc2ea2237657", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00425', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司2022年1月1日以$1,880,000取得面額$2,000,000，票面利率8%之公司債，作為按攤銷後 成本衡量之投資，該公司債每年6月30日及12月31日各付息一次，假設市場利率10%，試問 2022年底該筆債券投資之帳面金額為何？（本題不考慮減損）', '["$1,829,408", "$1,840,000", "$1,908,700", "$1,920,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "5e8d2b41a0ff", "answer_pdf_sha1": "fc2ea2237657", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00426', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司成立於2021年初，其於2021年度銷售電腦之收入為$2,300,000，銷售時承諾保證型保固2 年，估計2021年度及2022年度電腦送回維修之成本占銷貨收入金額之百分比分別為3%與3.5%。 若2021年度實際發生之維修成本為$56,000，則甲公司2021年底產品保證負債準備之餘額為：', '["$13,000", "$69,000", "$93,500", "$149,500"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "5e8d2b41a0ff", "answer_pdf_sha1": "fc2ea2237657", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00427', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司成立於2020年初，近年存貨成本的資料如下：2020年底成本$261,000，淨變現價值$255,000； 2021 年底成本$313,000，淨變現價值$315,000。另假設甲公司以備抵存貨跌價損失項目記錄期末 存貨之評價結果，則2021年底存貨評價分錄應為：', '["借記：銷貨成本$6,000；貸記：備抵存貨跌價損失$6,000", "借記：備抵存貨跌價損失$6,000；貸記：銷貨成本$6,000", "借記：銷貨成本$8,000；貸記：備抵存貨跌價損失$8,000", "借記：備抵存貨跌價損失$8,000；貸記：銷貨成本$8,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "5e8d2b41a0ff", "answer_pdf_sha1": "fc2ea2237657", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00428', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '假設甲公司2019年底存貨高估$4,000，2020年底存貨低估$4,000，2021年底存貨低估$8,000，若 2019年至2021年所報導的淨利皆為$90,000，試問甲公司2019年至2021年正確的淨利應為：（本 題不考慮所得稅）', '["$86,000，$98,000，$94,000", "$94,000，$82,000，$86,000", "$86,000，$94,000，$98,000", "$86,000，$90,000，$102,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "5e8d2b41a0ff", "answer_pdf_sha1": "fc2ea2237657", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00429', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司持有$210,000之承兌匯票，承兌日期為2022年6月15日，承兌後60日付款，年利率為 7%。公司於2022年7月20日，將此票據向銀行辦理貼現，貼現利率為9%，則貼現金額應為： （以360天為基礎計算，取最接近整數之選項）', '["$208,688", "$210,591", "$211,122", "$211,138"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "5e8d2b41a0ff", "answer_pdf_sha1": "fc2ea2237657", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
